input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command",
    "value": [
      "/bin/bash",
      "-c",
      "exec /cockroach/cockroach start --logtostderr=INFO --certs-dir=/cockroach/cockroach-certs --advertise-host=$(POD_NAME).crdb-cluster.$(POD_NAMESPACE).svc.cluster.local --http-addr=0.0.0.0:8080 --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257"
    ]
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "certs",
      "mountPath": "/cockroach/cockroach-certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "certs",
        "secret": {
          "secretName": "cockroachdb-node-certs",
          "defaultMode": 256
        }
      }
    ]
  }
]' 2>&1

kubectl -n cockroachdb patch statefulset crdb-cluster --type='json' -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/livenessProbe/httpGet/scheme",
    "value": "HTTPS"
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/readinessProbe/httpGet/scheme",
    "value": "HTTPS"
  }
]' 2>&1

content.content:
{"failureThreshold":3,"httpGet":{"path":"/health","port":"http","scheme":"HTTPS"},"initialDelaySeconds":30,"periodSeconds":5,"successThreshold":1,"timeoutSeconds":1}
{"failureThreshold":2,"httpGet":{"path":"/health?ready=1","port":"http","scheme":"HTTPS"},"initialDelaySeconds":10,"periodSeconds":5,"successThreshold":1,"timeoutSeconds":1}
[{"name":"certs","secret":{"defaultMode":256,"secretName":"cockroachdb-node-certs"}}]

